svg.script:
{
  "@context": "https://schema.org",
  "@type": "Table",
  "name": "Provider Email Authentication Requirements",
  "description": "Comparison of bulk sender requirements from Google Gmail, Microsoft Outlook, and Yahoo Mail. All require SPF, DKIM, DMARC with p=none minimum for senders of 5,000+ emails/day. Google enforces 0.1% spam rate target with 0.3% maximum. Non-compliant mail faces rejection or spam filtering.",
  "publisher": {
    "@type": "Organization",
    "name": "InboxAlly",
    "url": "https://www.inboxally.com"
  },
  "about": [
    {
      "@type": "Thing",
      "name": "Google Gmail Bulk Sender Requirements",
      "description": "SPF, DKIM, DMARC required. Spam rate below 0.1%, max 0.3%. One-click unsubscribe required. Enforced Feb 2024, strict 5xx rejection Nov 2025.",
      "url": "https://support.google.com/a/answer/81126"
    },
    {
      "@type": "Thing",
      "name": "Microsoft Outlook Bulk Sender Requirements",
      "description": "SPF, DKIM, DMARC required. Spam rate below 0.3%. One-click unsubscribe strongly recommended. Enforced May 2025 with Junk routing first, then rejection.",
      "url": "https://techcommunity.microsoft.com/blog/microsoftdefenderforoffice365blog/strengthening-email-ecosystem-outlook%E2%80%99s-new-requirements-for-high%E2%80%90volume-senders/4399730"
    },
    {
      "@type": "Thing",
      "name": "Yahoo Mail Bulk Sender Requirements",
      "description": "SPF, DKIM, DMARC required. Spam rate below 0.3%. One-click unsubscribe required. Enforced Feb 2024 with gradual rollout.",
      "url": "https://senders.yahooinc.com/best-practices/"
    }
  ]
}
